INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'cdbd593d-1ba4-4959-a2b2-11e8feca756e',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorRT Experiment Tracking — Versioning Engines, Params, and Latency Across Precision Runs$escape$,
  $escape$TensorRT experiment tracking means more than logging loss curves — you're versioning engine build decisions that directly impact inference latency and throughput. Key params to capture per run: precision flags (`FP16`, `INT8`, `FP32`), `set_memory_pool_limit` workspace allocation, `optimization_level` (0–5), and dynamic shape profile bounds (min/opt/max per input tensor).

Log build time as a metric — it correlates tightly with `optimization_level` and spikes unexpectedly with large workspace limits. For INT8 runs, log the calibration algorithm (`IInt8EntropyCalibrator2` vs `IInt8MinMaxCalibrator`) and calibration dataset size, since these govern the accuracy-speed tradeoff.

Serialize the built engine via `builder.build_serialized_network()` and log it as an artifact alongside its calibration cache. Given the same CUDA version, driver, and GPU SKU, the same `.trt` file produces bit-identical inference — making runs truly reproducible.

Use MLflow's run comparison view to diff FP16 vs INT8 across builds. When you co-log a shared `eval_top1` accuracy metric with engine artifacts, the latency-accuracy frontier becomes immediately visible, letting you pick the right precision regime for your deployment SLA.$escape$,
  $escape$import mlflow, tensorrt as trt, time

with mlflow.start_run():
    mlflow.log_params({"precision": "fp16", "workspace_gb": 4, "opt_level": 3})

    config = builder.create_builder_config()
    config.set_flag(trt.BuilderFlag.FP16)
    config.set_memory_pool_limit(trt.MemoryPoolType.WORKSPACE, 4 << 30)
    config.builder_optimization_level = 3

    t0 = time.perf_counter()
    serialized = builder.build_serialized_network(network, config)
    mlflow.log_metric("build_time_s", round(time.perf_counter() - t0, 3))

    with open("model.trt", "wb") as f:
        f.write(serialized)
    mlflow.log_artifact("model.trt")
    mlflow.log_metrics({"p50_latency_ms": 4.2, "throughput_fps": 238, "eval_top1": 0.761})$escape$,
