INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '996cd127-c52c-4fda-a264-6baf3e540ec6',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorRT + MLflow — Tracking Engine Builds, Registering Plans, and Serving Optimized Models$escape$,
  $escape$TensorRT engines are platform-specific serialized `.plan` files — MLflow's model registry is the right place to version and distribute them. When building an engine, log your `BuilderConfig` hyperparameters as MLflow params: precision (`FP16`, `INT8`), `max_workspace_size`, calibration dataset hash, and CUDA compute capability. Log engine size and throughput benchmarks as metrics. Serialize the engine with `engine.serialize()` and log it as an artifact via `mlflow.log_artifact('model.plan')`. For serving, wrap TensorRT inference in a `mlflow.pyfunc` custom model: implement `load_context` to deserialize the plan with `runtime.deserialize_cuda_engine()` and `predict` to run inference via a persistent `IExecutionContext`. This pattern lets you A/B compare FP32 vs FP16 engines across the same ONNX source model, trace latency regressions per build, and deploy via MLflow's REST scoring server without modifying your inference wrapper. Use MLflow Projects to pin the ONNX export + `trtexec` conversion pipeline so engine builds are fully reproducible across driver versions.$escape$,
  $escape$import mlflow
import mlflow.pyfunc
import tensorrt as trt
import numpy as np

class TRTModel(mlflow.pyfunc.PythonModel):
    def load_context(self, context):
        runtime = trt.Runtime(trt.Logger(trt.Logger.WARNING))
        with open(context.artifacts["engine_path"], "rb") as f:
            self.engine = runtime.deserialize_cuda_engine(f.read())
        self.context = self.engine.create_execution_context()

    def predict(self, context, model_input):
        # bind inputs/outputs and run inference
        bindings = []
        for i in range(self.engine.num_bindings):
            shape = self.engine.get_binding_shape(i)
            dtype = trt.nptype(self.engine.get_binding_dtype(i))
            mem = np.ascontiguousarray(model_input.values if i == 0 else np.empty(shape, dtype=dtype))
            import pycuda.driver as cuda
            bindings.append(int(cuda.mem_alloc(mem.nbytes)))
        self.context.execute_v2(bindings=bindings)
        return bindings

with mlflow.start_run():
    mlflow.log_params({"precision": "FP16", "workspace_mb": 4096, "compute_cap": "8.6"})
    mlflow.log_artifact("model.plan", artifact_path="engine")
    mlflow.pyfunc.log_model("trt_model", python_model=TRTModel(),
        artifacts={"engine_path": "model.plan"})
    mlflow.register_model("runs:/<run_id>/trt_model", "ResNet50-TRT-FP16")$escape$,
  $escape$python$escape$,
