INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '44d3cd36-1dd0-4e6e-9136-07526eb37a0b',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorRT + DVC — Versioning Engines, Calibration Data, and Reproducible Build Pipelines$escape$,
  $escape$TensorRT engine files (.engine) are platform-specific artifacts — built against a fixed GPU architecture, CUDA version, and TRT version. Without versioning, a calibration dataset change silently invalidates your INT8 engine and you won't know until accuracy regresses in prod.

DVC solves this by treating your ONNX checkpoint, INT8 calibration cache, and serialized .engine as first-class versioned artifacts. Define a pipeline in dvc.yaml with three stages: export (PyTorch → ONNX), calibrate (generate calibration.cache via IInt8EntropyCalibrator2), and build (trtexec or Python API → engine.trt). Each stage hashes its inputs — if the ONNX graph or calibration set changes, only downstream stages re-run.

Store large .engine files on a DVC remote (S3, Azure Blob, GCS) so CI pulls the exact engine for a given commit without rebuilding from scratch on every runner. Tag experiments with dvc exp run --set-param precision=fp16 to compare FP16 vs INT8 latency reproducibly across GPU generations — critical when validating on A100 vs T4 before fleet rollout.$escape$,
  $escape$# dvc.yaml
stages:
  export_onnx:
    cmd: python export.py --input model.pt --output model.onnx --opset 17
    deps: [model.pt, export.py]
    outs: [model.onnx]

  calibrate:
    cmd: python calibrate.py --data calib_data/ --cache calibration.cache
    deps: [model.onnx, calib_data/]
    outs: [calibration.cache]

  build_engine:
    cmd: >-
      trtexec --onnx=model.onnx
        --int8 --calib=calibration.cache
        --saveEngine=engine.trt
        --workspace=4096
    deps: [model.onnx, calibration.cache]
    outs: [engine.trt]$escape$,
  $escape$bash$escape$,
