INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '616d5e46-edc2-4815-a231-c55cf4c1d6e6',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorRT Model Registry — Versioning .engine Files from Staging to Production$escape$,
  $escape$TensorRT engines are not portable artifacts — a `.engine` file serialized on an A100 (sm_80) will silently fail or crash on an H100 (sm_90). Your registry must treat GPU architecture, TRT version, and CUDA version as first-class metadata, not optional annotations.

MLflow is the pragmatic choice here. Log the serialized engine via `mlflow.log_artifact()`, then tag each `ModelVersion` with `gpu_arch`, `trt_version`, and `precision` (fp16/int8). Staging means the engine has passed latency and accuracy benchmarks on a representative GPU; production means it has been validated on the exact target hardware SKU.

Approval workflow: block `transition_model_version_stage(..., stage='Production')` behind a CI gate that spins up a Triton Inference Server instance, loads the engine into a versioned model repository directory (e.g. `models/resnet50/2/model.plan`), and runs a smoke benchmark with `perf_analyzer`. Only on green does the MLflow stage transition fire. Never promote an engine that was built on a different `sm_` target than your serving fleet.$escape$,
  $escape$import mlflow
import tensorrt as trt

def register_trt_engine(engine_path: str, gpu_arch: str) -> str:
    with mlflow.start_run() as run:
        mlflow.set_tags({
            "gpu_arch": gpu_arch,           # e.g. "sm_89"
            "trt_version": trt.__version__,  # e.g. "8.6.1"
            "precision": "fp16",
        })
        mlflow.log_artifact(engine_path, artifact_path="trt_engine")

    client = mlflow.tracking.MlflowClient()
    mv = client.create_model_version(
        name="resnet50-trt",
        source=f"runs:/{run.info.run_id}/trt_engine",
        run_id=run.info.run_id,
    )
    client.transition_model_version_stage(
        name="resnet50-trt", version=mv.version, stage="Staging"
    )
    return mv.version$escape$,
  $escape$python$escape$,
