INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e3b74708-8a44-4d09-a105-d1764194bc1d',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorRT INT8 Calibration — Squeezing Latency Without Destroying Accuracy$escape$,
  $escape$TensorRT's INT8 quantization reduces model weights and activations from FP32/FP16 to 8-bit integers, cutting inference latency by 2–4x on Ampere/Ada GPUs. The key is calibration: TensorRT profiles activation ranges on a representative dataset to compute per-tensor scale factors, minimizing the KL-divergence between FP32 and INT8 distributions.

Use `IInt8EntropyCalibrator2` for most vision models — it's more robust than MinMax for long-tailed distributions. Feed at least 500 representative samples; fewer causes poor scale estimates and accuracy collapse. Set `builder_config.set_flag(trt.BuilderFlag.INT8)` and attach your calibrator before calling `builder.build_serialized_network()`.

For mixed precision, use `network.get_layer(i).precision = trt.DataType.FLOAT` to pin sensitive layers (e.g., detection heads, softmax) back to FP32. This preserves top-1 accuracy within 0.5% of baseline while retaining most latency gains.

Always benchmark with `trtexec --iterations=1000 --warmUp=500` — cold-start numbers are meaningless. Profile with Nsight Systems to identify any INT8 fallbacks that silently degrade throughput.$escape$,
  $escape$import tensorrt as trt
import numpy as np

class EntropyCalibrator(trt.IInt8EntropyCalibrator2):
    def __init__(self, data_loader, cache_file="calibration.cache"):
        super().__init__()
        self.data_loader = iter(data_loader)
        self.cache_file = cache_file
        self.device_input = None

    def get_batch_size(self): return 8

    def get_batch(self, names):
        try:
            batch = next(self.data_loader).cuda()
            import pycuda.driver as cuda
            self.device_input = cuda.mem_alloc(batch.nbytes)
            cuda.memcpy_htod(self.device_input, batch.numpy())
            return [int(self.device_input)]
        except StopIteration:
            return None

    def read_calibration_cache(self):
        if os.path.exists(self.cache_file):
            return open(self.cache_file, "rb").read()

    def write_calibration_cache(self, cache):
        open(self.cache_file, "wb").write(cache)

# Attach to builder
builder_config.set_flag(trt.BuilderFlag.INT8)
builder_config.int8_calibrator = EntropyCalibrator(val_loader)$escape$,
  $escape$python$escape$,
