INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1783f14c-544d-431b-b4c4-3bead0fb1f63',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorRT + Ray Serve — Scaling Engine Replicas Without CUDA Context Conflicts$escape$,
  $escape$TensorRT engines are serialized, device-specific binaries — they cannot be shared across processes without re-deserializing per CUDA context. Ray Serve's actor-based deployment model handles this correctly: each replica independently calls `trt.Runtime().deserialize_cuda_engine()`, creating an isolated `IExecutionContext` per GPU. Set `num_gpus: 1` in `ray_actor_options` to guarantee exclusive GPU allocation, preventing context contention that causes silent inference failures when two contexts share a device without explicit stream pinning.

For Ray Tune HPO, target TensorRT-specific knobs: `BuilderConfig.max_workspace_size`, INT8 calibration batch count, and dynamic shape profile bounds via `set_shape`. Tune against P99 latency measured through `trt.IProfiler` rather than accuracy alone — INT8 quantization can hide regressions that only surface under production batch distributions.

Engine versioning is clean with Ray Serve: assign a distinct `route_prefix` per `.engine` file in `serve.run()`, enabling zero-downtime swaps without tearing down the cluster or invalidating warm GPU contexts. Pair with Ray's placement groups to co-locate preprocessing actors and TensorRT inference replicas on the same node, eliminating PCIe transfer overhead between pipeline stages.$escape$,
  $escape$import tensorrt as trt
from ray import serve

@serve.deployment(num_replicas=2, ray_actor_options={"num_gpus": 1})
class TRTEngineReplica:
    def __init__(self, engine_path: str):
        logger = trt.Logger(trt.Logger.WARNING)
        runtime = trt.Runtime(logger)
        with open(engine_path, "rb") as f:
            self.engine = runtime.deserialize_cuda_engine(f.read())
        self.context = self.engine.create_execution_context()

    async def __call__(self, request):
        # bind inputs: self.context.set_tensor_address(name, device_ptr)
        return {"num_io_tensors": self.engine.num_io_tensors}

serve.run(TRTEngineReplica.bind("/models/resnet50_int8.engine"), route_prefix="/v1/infer")$escape$,
  $escape$python$escape$,
