INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '05ba4885-6d31-4450-9df4-40b459bcc6c4',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorRT Hyperparameter Search — Why Bayesian Beats Grid When Every Build Costs Minutes$escape$,
  $escape$TensorRT's engine build config is its own hyperparameter space: workspace allocation (`MemoryPoolType.WORKSPACE`), precision flags (`BuilderFlag.FP16`, `BuilderFlag.INT8`), and dynamic shape profiles interact non-linearly with inference latency. Grid search is prohibitive — a 5×2×4 sweep across workspace sizes, precision modes, and batch profiles means 40 full engine builds, each taking several minutes on large models.

Random search improves coverage but wastes trials on already-explored regions. Bayesian search via Optuna's TPE sampler learns the latency surface from each completed build and steers subsequent trials toward promising configs — typically converging in 15–20 trials versus 30+ for random.

The TensorRT-specific accelerant: share a `ITimingCache` across all trials. Kernel tactic profiling dominates build time. Serializing the cache after each trial and reloading it in the next cuts redundant per-layer profiling by 60–80% on repeated architectures. For early stopping, Optuna's `MedianPruner` abandons trials whose intermediate latency already exceeds the running median — avoiding the full benchmark penalty on clearly inferior configs.$escape$,
  $escape$import tensorrt as trt, optuna, pathlib
CACHE = pathlib.Path("tactic_cache.bin")
TRT_LOGGER = trt.Logger(trt.Logger.WARNING)

def objective(trial):
    cfg = trt.Builder(TRT_LOGGER).create_builder_config()
    cfg.set_memory_pool_limit(trt.MemoryPoolType.WORKSPACE,
                              trial.suggest_int("ws_mb", 512, 4096, step=512) << 20)
    if trial.suggest_categorical("fp16", [True, False]):
        cfg.set_flag(trt.BuilderFlag.FP16)
    tc = cfg.create_timing_cache(CACHE.read_bytes() if CACHE.exists() else b"")
    cfg.set_timing_cache(tc, ignore_mismatch=False)
    latency = build_and_time(cfg)  # build engine + benchmark; serialize cache after
    CACHE.write_bytes(tc.serialize())
    return latency

optuna.create_study(direction="minimize", sampler=optuna.samplers.TPESampler(),
    pruner=optuna.pruners.MedianPruner(n_startup_trials=5)).optimize(objective, n_trials=25)$escape$,
  $escape$python$escape$,
