INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9a8101bb-025e-4f99-802d-f53c2138c151',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorRT in Prod — Detecting Drift and Performance Degradation with IProfiler$escape$,
  $escape$TensorRT engines are compiled artifacts — they don't retrain or adapt. That makes drift invisible unless you explicitly instrument your inference pipeline. For prediction drift, snapshot output tensor statistics after each `enqueueV3()` call: compute running mean and std over a sliding window, then flag when the Z-score of the current batch mean exceeds a threshold. For data drift, validate input tensor distributions before `setTensorAddress()` — specifically watch for values outside the min/opt/max shape ranges defined in your `IOptimizationProfile`, which cause silent fallback to slower kernels. For performance degradation, implement `trt.IProfiler` to get per-layer execution times. This is the only way to distinguish GPU thermal throttling from a kernel regression introduced by a driver update or new engine rebuild. Pair the profiler output with `cudaEventElapsedTime` to get wall-clock latency independent of TRT's internal accounting. Persist baselines per engine version (use `ICudaEngine::getName()` as the key) so drift comparisons survive redeployments.$escape$,
  $escape$import tensorrt as trt
import numpy as np
from collections import deque

class ProdProfiler(trt.IProfiler):
    def __init__(self, sla_ms=8.0):
        super().__init__()
        self.sla_ms = sla_ms
        self.total_ms = 0.0

    def report_layer_time(self, layer_name: str, ms: float):
        self.total_ms += ms

    def check_sla(self) -> bool:
        exceeded = self.total_ms > self.sla_ms
        self.total_ms = 0.0
        return exceeded

output_window = deque(maxlen=500)

def monitor_inference(context, output_buf, baseline_mean, baseline_std):
    context.execute_v2(bindings=[...])  # your actual bindings
    out = np.copy(output_buf)
    output_window.append(out.mean())
    if len(output_window) == 500:
        z = abs(np.mean(output_window) - baseline_mean) / (baseline_std + 1e-9)
        if z > 3.0:
            raise RuntimeError(f"Prediction drift detected: Z={z:.2f}")$escape$,
  $escape$python$escape$,
