INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b55b3003-5dc8-4eee-b35a-1804752a7e20',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorRT CI/CD — Engine Rebuild Gates, Polygraphy Accuracy Checks, and Safe Deployment$escape$,
  $escape$TensorRT engines are GPU-architecture-specific — a rebuild is mandatory whenever the base model changes, CUDA compute capability shifts, or TensorRT version bumps. CI/CD pipelines must treat `.engine` artifacts as derived outputs, never as source artifacts.

A robust pipeline enforces three sequential gates:

1. **Build gate:** Convert the updated ONNX checkpoint to a TensorRT engine via `trtexec` with pinned `--optShapes`, `--fp16`, and `--workspace`. Commit these flags to your pipeline config to guarantee reproducibility across CI runners.

2. **Accuracy gate:** Run `polygraphy run <model.onnx> --trt --onnxrt --atol=1e-2 --rtol=1e-2` to diff TRT outputs against the ONNX reference. Numerical divergence is common after layer-fusion or INT8 calibration — catch it here, not in production.

3. **Latency gate:** Replay `trtexec --loadEngine --percentile=99 --iterations=500` and assert the p99 GPU compute time stays within SLA. Gate on p99, not mean — outliers kill production tail latency.

Store versioned `.engine` files in artifact storage tagged with TRT version, CUDA compute capability, and git SHA. Never deploy an engine built on a different GPU class than your production fleet.$escape$,
  $escape$import subprocess, sys

def trt_ci_gate(onnx_path: str, engine_path: str, p99_budget_ms: float = 5.0):
    subprocess.run([
        "trtexec", f"--onnx={onnx_path}", f"--saveEngine={engine_path}",
        "--fp16", "--optShapes=input:8x3x224x224", "--maxShapes=input:32x3x224x224",
    ], check=True)
    subprocess.run([
        "polygraphy", "run", onnx_path, "--trt", "--onnxrt",
        "--atol=1e-2", "--rtol=1e-2", "--fail-fast",
    ], check=True)
    out = subprocess.run([
        "trtexec", f"--loadEngine={engine_path}", "--percentile=99", "--iterations=500",
    ], capture_output=True, text=True, check=True).stdout
    for line in out.splitlines():
        if "GPU Compute Time" in line and "max =" in line:
            p99 = float(line.split("max =")[1].split("ms")[0].strip())
            if p99 > p99_budget_ms:
                sys.exit(f"Latency gate FAILED: {p99:.2f}ms > {p99_budget_ms}ms")$escape$,
  $escape$python$escape$,
