INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '07f2b061-9c12-4251-a342-1293f4381c9c',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorRT INT8 Calibration — Precision Trade-offs You Need to Know$escape$,
  $escape$TensorRT's INT8 mode can cut inference latency 2–4× over FP32, but naive activation quantizes poorly — you must supply a calibration dataset via IInt8EntropyCalibrator2 so TensorRT computes per-tensor dynamic ranges that minimize KL divergence. FP16 is safer: just set the BuilderFlag and TensorRT auto-selects which layers benefit; accuracy loss is typically <0.5% on modern Ampere/Ada GPUs with native FP16 tensor cores. INT8 requires 500–1000 representative batches through your calibrator, and the resulting calibration cache should be versioned alongside your engine — different GPU architectures produce different scales. Watch for layers TensorRT silently falls back to FP32 (e.g., SoftMax, certain normalizations); use trt.ILayer.precision and output_type to inspect or force precision per-layer. For structured sparsity (2:4 pattern), enable SPARSE_WEIGHTS — Ampere GPUs get near-2× speedup with zero calibration overhead, but you must pre-prune weights in PyTorch using torch.nn.utils.prune before export. Combining INT8 + sparsity rarely stacks perfectly; benchmark both paths with trtexec before committing.$escape$,
  $escape$import tensorrt as trt

logger = trt.Logger(trt.Logger.WARNING)
builder = trt.Builder(logger)
config = builder.create_builder_config()
config.set_memory_pool_limit(trt.MemoryPoolType.WORKSPACE, 1 << 30)

# Enable FP16 (safe default)
config.set_flag(trt.BuilderFlag.FP16)

# Enable INT8 + attach calibrator
config.set_flag(trt.BuilderFlag.INT8)
config.int8_calibrator = MyEntropyCalibrator2(
    data_loader=calib_loader,
    cache_file="calib_cache.bin"
)

# Enable 2:4 structured sparsity (Ampere+)
config.set_flag(trt.BuilderFlag.SPARSE_WEIGHTS)$escape$,
  $escape$python$escape$,
