INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3a1e2416-c12a-44b1-aaba-e8f47d43df48',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorRT A/B Testing — Shadow Deployment, Canary Releases, and Champion/Challenger$escape$,
  $escape$Running multiple TensorRT engines simultaneously is the foundation of production model experimentation. In a shadow deployment, you serialize both engines via `trt.Builder` with identical `INetworkDefinition` inputs, execute the challenger engine in parallel using a separate `IExecutionContext`, but only return the champion's output. Compare logits or latency offline without affecting users.

For canary releases, partition traffic by request ID hash: route 5% to the challenger `IExecutionContext` and 95% to the champion, both sharing the same `ICudaEngine` loaded from distinct `.plan` files. Use `cudaStreamCreate()` per context to prevent stream contention — critical when both engines target the same GPU.

Champion/challenger promotion hinges on metrics: measure P99 latency via `cudaEventElapsedTime()` and track accuracy deltas against a labeled holdout set. Once the challenger exceeds the champion on both dimensions for a statistically significant window, swap the `.plan` file path in your engine loader and reload via `runtime->deserializeCudaEngine()` without downtime. Always version `.plan` files by `trtexec` build hash to ensure reproducibility across engine swaps.$escape$,
  $escape$import tensorrt as trt
import pycuda.driver as cuda
import numpy as np

runtime = trt.Runtime(trt.Logger(trt.Logger.WARNING))

with open("champion.plan", "rb") as f:
    champion_engine = runtime.deserialize_cuda_engine(f.read())
with open("challenger.plan", "rb") as f:
    challenger_engine = runtime.deserialize_cuda_engine(f.read())

champion_ctx = champion_engine.create_execution_context()
challenger_ctx = challenger_engine.create_execution_context()

stream_a = cuda.Stream()
stream_b = cuda.Stream()

def route(request_id: int, input_buf):
    is_canary = (hash(request_id) % 100) < 5
    ctx = challenger_ctx if is_canary else champion_ctx
    stream = stream_b if is_canary else stream_a
    ctx.execute_async_v2(bindings=input_buf, stream_handle=stream.handle)
    stream.synchronize()
    return is_canary$escape$,
  $escape$python$escape$,
