INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ea749fda-bd44-4c19-94e8-13e05cd8a8ef',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorRT Inference Pipelines — Validating Inputs and Detecting Data Drift Before Execution$escape$,
  $escape$TensorRT engines are compiled for fixed input shapes and data types — feeding mismatched tensors silently produces garbage outputs or crashes at `context->enqueueV3()`. Build a lightweight validation layer that checks binding metadata against incoming data before every inference call.

Use `engine->getTensorDataType(name)` and `engine->getTensorShape(name)` to extract expected specs at startup, then compare against your runtime input tensors. For drift detection, maintain a rolling mean and variance of input feature distributions using Welford's online algorithm. If the z-score of a feature's current batch mean exceeds a threshold (e.g. 3σ), flag it before the tensor ever hits the engine.

This matters because TensorRT's optimization profiles (`IOptimizationProfile`) define min/opt/max shape ranges — inputs near the boundaries trigger re-selection of the closest profile, degrading latency. Catching this at the pipeline level lets you reroute or rescale before paying the profile-switch cost.

Store per-feature stats in a circular buffer on the host; the overhead is negligible compared to `cudaMemcpyAsync` and kernel launch latency.$escape$,
  $escape$// Validate input tensor against TensorRT engine binding
void validateInput(nvinfer1::ICudaEngine* engine, const char* name,
                   nvinfer1::Dims actualDims, nvinfer1::DataType actualDtype) {
    auto expectedDtype = engine->getTensorDataType(name);
    auto expectedDims  = engine->getTensorShape(name);

    if (actualDtype != expectedDtype)
        throw std::runtime_error(std::string(name) + ": dtype mismatch");

    for (int i = 0; i < expectedDims.nbDims; ++i) {
        if (expectedDims.d[i] != -1 && expectedDims.d[i] != actualDims.d[i])
            throw std::runtime_error(std::string(name) + ": shape mismatch at dim " + std::to_string(i));
    }
}

// Welford online drift check (per feature)
bool isDrifted(WelfordState& state, float newMean, float sigmaThreshold = 3.0f) {
    float z = std::abs(newMean - state.mean) / (std::sqrt(state.variance) + 1e-8f);
    state.update(newMean);
    return z > sigmaThreshold;
}$escape$,
  $escape$cpp$escape$,
